import "./landing_page.css"

import { useState, useEffect, useRef, useCallback } from "react";

/* ============================================================
   صور الأعمال — مضمّنة كـ base64 لضمان ظهورها فوراً بلا تأخير
   ============================================================ */
const IMG_STORE =
  "data:image/jpeg;base64,";
const IMG_T2 =
  "data:image/jpeg;base64,";
const IMG_PIZZA =
  "data:image/jpeg;base64,";

// تذكر استيراد الصور هنا في أعلى الملف إذا لم تكن مستوردة سابقاً، مثل:
// import IMG_PIZZA from './assets/pizza.jpg';
// import IMG_T2 from './assets/t2.jpg';
// import IMG_STORE from './assets/store.jpg';

const WHATSAPP_NUMBER = "905340242575";
const waLink = (msg) =>
  `https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`;

/* أيقونة واتساب SVG بسيطة */
function WhatsIcon({ size = 20 }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="currentColor"
      aria-hidden="true"
    >
      <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z" />
    </svg>
  );
}

function CheckIcon() {
  return (
    <svg
      width={22}
      height={22}
      viewBox="0 0 16 16"
      fill="none"
      aria-hidden="true"
    >
      <circle cx="8" cy="8" r="8" fill="#0ef686" fillOpacity="0.18" />
      <path
        d="M4.5 8.2L6.7 10.4L11.5 5.4"
        stroke="#07c26e"
        strokeWidth="1.6"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

/* بطاقة مشروع حقيقي */
function ProjectCard({ image, sector, title, desc, liveUrl }) {
  return (
    <div className="proj-card">
      <a
        href={liveUrl}
        target="_blank"
        rel="noopener noreferrer"
        className="proj-img-wrap"
        aria-label={`فتح موقع ${title} المباشر`}
      >
        <img src={image} alt={`معاينة موقع ${title}`} loading="lazy" />
        <span className="live-pill">
          <span className="live-dot" />
          عرض مباشر
        </span>
      </a>
      <div className="proj-body">
        <p className="proj-sector">{sector}</p>
        <h3>{title}</h3>
        <p className="proj-desc">{desc}</p>
        <a
          href={liveUrl}
          target="_blank"
          rel="noopener noreferrer"
          className="proj-link"
        >
          زيارة الموقع ←
        </a>
      </div>
    </div>
  );
}

export default function Landing_page() {
  const [shown, setShown] = useState({});
  const refs = useRef({});

  useEffect(() => {
    const currentRefs = refs.current;
    const obs = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (e.isIntersecting && e.target.dataset.key) {
            setShown((s) => ({ ...s, [e.target.dataset.key]: true }));
          }
        });
      },
      { threshold: 0.15 },
    );

    Object.values(currentRefs).forEach((el) => el && obs.observe(el));

    return () => obs.disconnect();
  }, []);

  // تعديل الـ Ref Callback ليعمل بأمان دون كسر مرحلة الرندرة
  const reg = useCallback(
    (key) => (el) => {
      if (el) {
        el.dataset.key = key;
        refs.current[key] = el;
      }
    },
    [],
  );

  const projects = [
    {
      key: "pizza",
      image: typeof IMG_T2 !== "undefined" ? IMG_T2 : "",
      sector: "مطعم · ألمانيا",
      title: "Angelo Della Pizza",
      desc: "موقع مطعم إيطالي — قائمة طعام تفاعلية وطلب مباشر من الجوال.",
      liveUrl: "https://angolodella-pizza.vercel.app/",
    },
    {
      key: "t2",
      image: typeof IMG_PIZZA !== "undefined" ? IMG_PIZZA : "",
      sector: "قطع غيار سيارات · العراق",
      title: "T2 Accessories",
      desc: "متجر إلكتروني لقطع غيار واكسسوارات السيارات مع بحث وتصنيف للمنتجات.",
      liveUrl: "https://t2-accessories.vercel.app",
    },
    {
      key: "store",
      image: typeof IMG_STORE !== "undefined" ? IMG_STORE : "",
      sector: "متاجر إلكترونية · أثاث وديكور",
      title: "Star Center",
      desc: "متجر أثاث ومنتجات منزلية بتصميم عصري يرفع نسبة الشراء.",
      liveUrl: "https://enes-mobilia.vercel.app/",
    },
  ];

  const heroMsg = "مرحباً، شفت موقعكم وحاب أطلب موقع لمشروعي 🚀";
  const ctaMsg = "أهلاً، جاهز أبدأ بموقعي الآن — كم التفاصيل والمدة؟";

  return (
    <div className="page" dir="rtl" lang="ar">
      {/* زر واتساب عائم */}
      <a
        className="float-wa"
        href={waLink(ctaMsg)}
        target="_blank"
        rel="noopener noreferrer"
        aria-label="تواصل عبر واتساب"
      >
        <WhatsIcon size={28} />
      </a>

      {/* ============ HERO ============ */}
      <section className="hero">
        <div className="hero-bg" />
        <span className="badge">✦ مواقع احترافية · تسليم خلال 7 أيام</span>
        <h1>
          موقعك هو أقوى
          <br />
          <span className="grad">موظف مبيعات</span>
          <br />
          يعمل 24 ساعة بلا إجازة
        </h1>
        <p className="sub">
          نحوّل زوار صفحتك إلى عملاء حقيقيين — بأسعار تبدأ من{" "}
          <strong>200$</strong> فقط، وتسليم سريع بلا تعقيد.
        </p>

        <a
          className="btn-wa"
          href={waLink(heroMsg)}
          target="_blank"
          rel="noopener noreferrer"
        >
          <WhatsIcon />
          احصل على موقعك الآن
        </a>

        <div className="trust-bar">
          <span>
            <i className="dot" /> تسليم خلال أسبوع
          </span>
          <span>
            <i className="dot" /> دعم مجاني بعد التسليم
          </span>
          <span>
            <i className="dot" /> متجاوب مع كل الأجهزة
          </span>
        </div>
      </section>

      {/* ============ PAIN ============ */}
      <section className="pain" ref={reg("pain")}>
        <div className={`reveal ${shown.pain ? "in" : ""}`}>
          <h2>عملك موجود — لكن لا أحد يجده أونلاين</h2>
          <div className="pain-row">
            <div className="pain-item">
              <span className="pain-ic">✋</span>
              <p>عميلك يبحث عنك ولا يجدك، فيذهب لمنافسك مباشرة.</p>
            </div>
            <div className="pain-item">
              <span className="pain-ic">💸</span>
              <p>دفعت لمصمم سابقاً والنتيجة موقع لا يحقق أي مبيعات.</p>
            </div>
            <div className="pain-item">
              <span className="pain-ic">📵</span>
              <p>تعتمد فقط على السوشيال ميديا، وهي تتغير وتُحجب.</p>
            </div>
          </div>
        </div>
      </section>

      {/* ============ WORK ============ */}
      <section className="work" ref={reg("work")} id="work">
        <div className={`reveal ${shown.work ? "in" : ""}`}>
          <p className="eyebrow">أعمال حقيقية · عملاء حقيقيون</p>
          <h2><span className="admin">أخر ثلاث عملاء</span> نتائج تتكلم عن نفسها </h2>
        </div>
        <div className="proj-grid">
          {projects.map((p, i) => (
            <div
              key={p.key}
              ref={reg(`proj-${i}`)}
              className={`reveal ${shown[`proj-${i}`] ? "in" : ""}`}
              style={{ transitionDelay: `${i * 90}ms` }}
            >
              <ProjectCard {...p} />
            </div>
          ))}
        </div>
      </section>

      {/* ============ VALUE ============ */}
      <section className="value" ref={reg("value")}>
        <div className={`reveal ${shown.value ? "in" : ""}`}>
          <div className="value-grid">
            <div className="value-card">
              <CheckIcon />
              <p>تصميم احترافي مطابق لهوية عملك</p>
            </div>
            <div className="value-card">
              <CheckIcon />
              <p>سرعة تحميل عالية تحافظ على عميلك</p>
            </div>
            <div className="value-card">
              <CheckIcon />
              <p>زر واتساب جاهز لاستقبال طلباتك فوراً</p>
            </div>
            <div className="value-card">
              <CheckIcon />
              <p>تسليم خلال أسبوع واحد فقط</p>
            </div>
          </div>
        </div>
      </section>

      {/* ============ FINAL CTA ============ */}
      <section className="cta" ref={reg("cta")}>
        <div className={`reveal ${shown.cta ? "in" : ""}`}>
          <h2>جاهز يبدأ موقعك هذا الأسبوع؟</h2>
          <p>راسلنا الآن على واتساب واحصل على عرض سعر فوري لمشروعك.</p>
          <a
            className="btn-wa lg"
            href={waLink(ctaMsg)}
            target="_blank"
            rel="noopener noreferrer"
          >
            <WhatsIcon size={22} />
            تواصل معنا على واتساب
          </a>
        </div>
      </section>

      <footer>
        <p>© 2026 — جميع الحقوق محفوظة</p>
      </footer>
    </div>
  );
}
